const body = {
  model: "sonar-pro",
  messages: [
    {
      role: "system",
      content: "Du bist ein erfahrener IT-Sicherheitsjournalist mit Fokus auf Deutschland und Europa. Recherchiere praezise, faktenbasiert und vollstaendig auf Deutsch."
    },
    {
      role: "user",
      content: "Was ist das wichtigste und aktuellste Ereignis aus den Bereichen Cybersecurity, KI-Sicherheit oder kritische Technologie der letzten 24-48 Stunden mit Relevanz fuer Deutschland oder Europa? Berichte sehr detailliert: 1) Was genau ist passiert? 2) Wer ist betroffen (Firmennamen, Behoerden, wie viele Nutzer/Systeme)? 3) Was sind die technischen Details und Hintergruende? 4) Was sollten deutsche Unternehmen und Nutzer jetzt konkret tun? Nenne bis zu 3 Quell-URLs. Antworte vollstaendig auf Deutsch mit allen verfuegbaren Fakten und Zahlen."
    }
  ]
};

return [{ json: { body: JSON.stringify(body) } }];

const perplexityResult = $('Perplexity Recherche').first().json.choices[0].message.content;
const today = new Date().toISOString().split('T')[0];

const prompt = `Schreibe einen professionellen deutschen Cybersecurity-Blog-Post fuer sicherheit.ai.

RECHERCHE-BASIS (Perplexity):
${perplexityResult}

HEUTIGES DATUM: ${today}

WICHTIG: Antworte NUR mit dem rohen JSON-Objekt. KEIN Markdown, KEIN Backtick-Block, KEINE Erklaerung davor oder danach. Nur das pure JSON.

Das JSON muss exakt diese Felder haben:
{
  "slug": "url-slug-nur-kleinbuchstaben-und-bindestriche-maximal-60-zeichen",
  "title": "Klarer praegnanter Titel maximal 80 Zeichen",
  "excerpt": "Zwei praezise informative Saetze als Artikel-Teaser. Maximal 220 Zeichen.",
  "content": "<h2 id=\\"was-passiert\\">Was ist passiert?</h2><p>Vollstaendiger Artikel mindestens 700 Woerter als HTML. Nutze h2 und h3 Tags mit id-Attributen. Sachlich, faktisch, mit Zahlen, Firmennamen, Zeitangaben. Konkrete Handlungsempfehlungen am Ende.</p><h2 id=\\"technische-details\\">Technische Details</h2><p>...</p><h2 id=\\"was-tun\\">Was sollten Sie jetzt tun?</h2><p>...</p>",
  "category": "KATEGORIE_HIER",
  "categoryColor": "#FARBE_HIER",
  "categoryBg": "rgba(r,g,b,0.1)",
  "author": "sicherheit.ai Redaktion",
  "authorRole": "KI-recherchiert & kuratiert",
  "publishedAt": "${today}",
  "readTime": 8,
  "imageGradient": "linear-gradient(135deg, #060B18 0%, #0D1A3A 100%)",
  "badge": null,
  "badgeColor": null,
  "tags": ["tag1", "tag2", "tag3", "tag4"],
  "faqs": [
    {"q": "Wichtige Frage zum Thema?", "a": "Vollstaendige hilfreiche Antwort."},
    {"q": "Zweite relevante Frage?", "a": "Antwort."},
    {"q": "Dritte Frage fuer Einsteiger?", "a": "Verstaendliche Antwort."}
  ],
  "sources": [{"title": "Quellenname", "url": "https://beispiel.de"}]
}

Kategorie-Auswahl (waehle die passendste):
- CVE/Sicherheitsluecke: category=Schwachstelle, categoryColor=#FF9632, categoryBg=rgba(255,150,50,0.1), imageGradient=linear-gradient(135deg, #1A0800 0%, #2A1200 100%)
- Hack/Datenpanne/Cyberangriff: category=Incident, categoryColor=#FF2D6F, categoryBg=rgba(255,45,111,0.1), imageGradient=linear-gradient(135deg, #1A0010 0%, #2A0020 100%)
- Gesetz/DSGVO/NIS2/AI Act: category=Regulierung, categoryColor=#7890FF, categoryBg=rgba(100,120,255,0.12), imageGradient=linear-gradient(135deg, #060B18 0%, #0A1230 100%)
- KI/ML Sicherheit: category=KI-Sicherheit, categoryColor=#00F0FF, categoryBg=rgba(0,240,255,0.1), imageGradient=linear-gradient(135deg, #001A1A 0%, #003333 100%)
- APT/Bedrohungsakteur: category=Bedrohung, categoryColor=#FF2D6F, categoryBg=rgba(255,45,111,0.1), imageGradient=linear-gradient(135deg, #1A0010 0%, #2A0020 100%)
- Bericht/Studie/Analyse: category=Analyse, categoryColor=#9664FF, categoryBg=rgba(150,100,255,0.1), imageGradient=linear-gradient(135deg, #0D0820 0%, #1A1030 100%)
- Allgemeine Tech-News: category=News, categoryColor=#78C864, categoryBg=rgba(120,200,100,0.1), imageGradient=linear-gradient(135deg, #060E08 0%, #0A1A0E 100%)

Falls es sich um eine kritische CVE handelt, setze badge=CVSS Score (z.B. CVSS 9.8) und badgeColor=#FF2D6F.`;

const body = {
  model: "claude-opus-4-6",
  max_tokens: 4000,
  messages: [{
    role: "user",
    content: prompt
  }]
};

return [{ json: { body: JSON.stringify(body) } }];

const raw = $input.first().json.content[0].text;

let clean = raw.trim();

// Entferne Markdown-Wrapper die Claude manchmal hinzufuegt
if (clean.startsWith('```json')) {
  clean = clean.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
} else if (clean.startsWith('```')) {
  clean = clean.replace(/^```\s*/, '').replace(/\s*```$/, '').trim();
}

// Falls noch Text vor dem JSON steht, extrahiere das JSON-Objekt
if (!clean.startsWith('{')) {
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) clean = match[0];
}

let post;
try {
  post = JSON.parse(clean);
} catch(e) {
  throw new Error('JSON Parse Fehler: ' + e.message + '\n\nErster Teil des Textes: ' + clean.slice(0, 300));
}

// Pflichtfelder garantieren
post.id = Date.now().toString();
post.publishedAt = post.publishedAt || new Date().toISOString().split('T')[0];
post.author = post.author || 'sicherheit.ai Redaktion';
post.authorRole = post.authorRole || 'KI-recherchiert & kuratiert';
post.tags = Array.isArray(post.tags) ? post.tags : [];
post.faqs = Array.isArray(post.faqs) ? post.faqs : [];
post.sources = Array.isArray(post.sources) ? post.sources : [];
post.readTime = Number(post.readTime) || 8;

// null-Felder entfernen
if (!post.badge) delete post.badge;
if (!post.badgeColor) delete post.badgeColor;

return [{ json: post }];

const fileData = $('GitHub Datei laden').first().json;
const sha = fileData.sha;

// GitHub gibt Base64 mit Zeilenumbruechen zurueck
const base64Clean = fileData.content.replace(/\n/g, '');
const currentJson = Buffer.from(base64Clean, 'base64').toString('utf8');
let posts = JSON.parse(currentJson);

const newPost = $('Response parsen').first().json;

// Duplikat-Schutz via Slug
const exists = posts.some(p => p.slug === newPost.slug);
if (!exists) {
  posts.unshift(newPost); // Neuester Post zuerst
}

// Maximal 100 Posts (verhindert riesige JSON-Datei)
posts = posts.slice(0, 100);

const updatedBase64 = Buffer.from(JSON.stringify(posts, null, 2)).toString('base64');

return [{
  json: {
    sha,
    updatedBase64,
    postTitle: newPost.title,
    postSlug: newPost.slug,
    totalPosts: posts.length
  }
}];
